struct Half2 {
  uint16_t x;
  uint16_t y;
};

static inline uint16_t float_to_half_bits(float value) {
  uint32_t bits;
  std::memcpy(&bits, &value, sizeof(bits));

  const uint32_t sign = (bits >> 16) & 0x8000u;
  uint32_t mantissa = bits & 0x007fffffu;
  int exp = static_cast<int>((bits >> 23) & 0xffu);

  if (exp == 255) {
    if (mantissa != 0) {
      return static_cast<uint16_t>(sign | 0x7e00u);
    }
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  exp = exp - 127 + 15;
  if (exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  if (exp <= 0) {
    if (exp < -10) {
      return static_cast<uint16_t>(sign);
    }
    mantissa |= 0x00800000u;
    const uint32_t shift = static_cast<uint32_t>(14 - exp);
    uint32_t half_mantissa = mantissa >> shift;
    if ((mantissa >> (shift - 1)) & 1u) {
      half_mantissa++;
    }
    return static_cast<uint16_t>(sign | half_mantissa);
  }

  uint16_t half_exp = static_cast<uint16_t>(exp << 10);
  uint16_t half_mantissa = static_cast<uint16_t>(mantissa >> 13);
  if (mantissa & 0x00001000u) {
    uint16_t rounded =
        static_cast<uint16_t>(sign | half_exp | half_mantissa);
    rounded = static_cast<uint16_t>(rounded + 1);
    return rounded;
  }
  return static_cast<uint16_t>(sign | half_exp | half_mantissa);
}

static inline float half_bits_to_float(uint16_t h) {
  const uint32_t sign = (static_cast<uint32_t>(h & 0x8000u)) << 16;
  uint32_t exp = (h >> 10) & 0x1fu;
  uint32_t mantissa = h & 0x03ffu;
  uint32_t bits = 0;

  if (exp == 0) {
    if (mantissa == 0) {
      bits = sign;
    } else {
      exp = 1;
      while ((mantissa & 0x0400u) == 0) {
        mantissa <<= 1;
        exp--;
      }
      mantissa &= 0x03ffu;
      exp = exp + (127 - 15);
      bits = sign | (exp << 23) | (mantissa << 13);
    }
  } else if (exp == 31) {
    bits = sign | 0x7f800000u | (mantissa << 13);
  } else {
    exp = exp + (127 - 15);
    bits = sign | (exp << 23) | (mantissa << 13);
  }

  float value;
  std::memcpy(&value, &bits, sizeof(value));
  return value;
}

static inline Half2 make_half2(float a, float b) {
  Half2 out;
  out.x = float_to_half_bits(a);
  out.y = float_to_half_bits(b);
  return out;
}

template <typename T>
struct KernelOps;

template <>
struct KernelOps<float> {
  static inline float add(float a, float b) { return a + b; }
  static inline float mul(float a, float b) { return a * b; }
  static inline float zero() { return 0.0f; }
  static inline float minus_one() { return -1.0f; }
  static inline bool equal(float a, float b) { return a == b; }
};

template <>
struct KernelOps<double> {
  static inline double add(double a, double b) { return a + b; }
  static inline double mul(double a, double b) { return a * b; }
  static inline double zero() { return 0.0; }
  static inline double minus_one() { return -1.0; }
  static inline bool equal(double a, double b) { return a == b; }
};

template <>
struct KernelOps<int32_t> {
  static inline int32_t add(int32_t a, int32_t b) {
    uint32_t ua = static_cast<uint32_t>(a);
    uint32_t ub = static_cast<uint32_t>(b);
    return static_cast<int32_t>(ua + ub);
  }
  static inline int32_t mul(int32_t a, int32_t b) {
    uint64_t ua = static_cast<uint32_t>(a);
    uint64_t ub = static_cast<uint32_t>(b);
    return static_cast<int32_t>(static_cast<uint32_t>(ua * ub));
  }
  static inline int32_t zero() { return 0; }
  static inline int32_t minus_one() { return -1; }
  static inline bool equal(int32_t a, int32_t b) { return a == b; }
};

template <>
struct KernelOps<int16_t> {
  static inline int16_t add(int16_t a, int16_t b) {
    uint16_t ua = static_cast<uint16_t>(a);
    uint16_t ub = static_cast<uint16_t>(b);
    return static_cast<int16_t>(static_cast<uint16_t>(ua + ub));
  }
  static inline int16_t mul(int16_t a, int16_t b) {
    uint32_t ua = static_cast<uint16_t>(a);
    uint32_t ub = static_cast<uint16_t>(b);
    return static_cast<int16_t>(static_cast<uint16_t>(ua * ub));
  }
  static inline int16_t zero() { return 0; }
  static inline int16_t minus_one() { return static_cast<int16_t>(-1); }
  static inline bool equal(int16_t a, int16_t b) { return a == b; }
};

template <>
struct KernelOps<Half2> {
  static inline Half2 add(Half2 a, Half2 b) {
    return make_half2(half_bits_to_float(a.x) + half_bits_to_float(b.x),
                      half_bits_to_float(a.y) + half_bits_to_float(b.y));
  }
  static inline Half2 mul(Half2 a, Half2 b) {
    return make_half2(half_bits_to_float(a.x) * half_bits_to_float(b.x),
                      half_bits_to_float(a.y) * half_bits_to_float(b.y));
  }
  static inline Half2 zero() { return make_half2(0.0f, 0.0f); }
  static inline Half2 minus_one() { return make_half2(-1.0f, -1.0f); }
  static inline bool equal(Half2 a, Half2 b) {
    return a.x == b.x && a.y == b.y;
  }
};

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else if ((strcmp(argv[i], "-w") == 0) ||
               (strcmp(argv[i], "--workgroup-stride") == 0)) {
      output->block_strided = true;
    } else if ((strcmp(argv[i], "-H") == 0) ||
               (strcmp(argv[i], "--host-alloc") == 0)) {
      output->host_allocated = true;
    } else if ((strcmp(argv[i], "-t") == 0) ||
               (strcmp(argv[i], "--use-os-timer") == 0)) {
      output->use_os_timer = true;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->device_index = static_cast<int>(value);
          arg_count++;
          break;
        case 1:
          output->wg_size = static_cast<int>(value);
          arg_count++;
          break;
        case 2:
          output->vecwidth = static_cast<unsigned int>(value);
          arg_count++;
          break;
        case 3:
          output->elements_per_wi = static_cast<unsigned int>(value);
          arg_count++;
          break;
        case 4:
          output->fusion_degree = static_cast<unsigned int>(value);
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

