void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

static inline double now_ms() {
  using clock = std::chrono::steady_clock;
  static const auto t0 = clock::now();
  auto dt = clock::now() - t0;
  return std::chrono::duration<double, std::milli>(dt).count();
}

template <int N, typename F>
double benchmark(F&& f) {
  double best = DBL_MAX;
  for (int i = 0; i < N; i++) {
    double v = f();
    if (v < best) best = v;
  }
  return best;
}

template <typename T>
void run_kernel_typed(void* buffer,
                      long logical_size,
                      size_t workgroupsize,
                      unsigned int elements_per_wi,
                      unsigned int fusion_degree,
                      int current_compute_iterations,
                      bool block_strided,
                      T seed) {
  if (logical_size <= 0) return;

  T* g_data = static_cast<T*>(buffer);
  const long total_threads = logical_size;
  const long num_groups =
      workgroupsize == 0 ? 0 : (total_threads / static_cast<long>(workgroupsize));
  const long big_stride = num_groups * static_cast<long>(workgroupsize) *
                          static_cast<long>(elements_per_wi);

#pragma omp parallel
  {
    std::vector<T> tmps(elements_per_wi);

#pragma omp for schedule(static)
    for (long tid = 0; tid < total_threads; tid++) {
      long idx;
      long stride;
      if (block_strided) {
        const long group = workgroupsize == 0
                               ? 0
                               : (tid / static_cast<long>(workgroupsize));
        const long local = workgroupsize == 0
                               ? 0
                               : (tid % static_cast<long>(workgroupsize));
        stride = static_cast<long>(workgroupsize);
        idx = group * static_cast<long>(workgroupsize) *
                  static_cast<long>(elements_per_wi) +
              local;
      } else {
        stride = total_threads;
        idx = tid;
      }

      for (unsigned int k = 0; k < fusion_degree; k++) {
        for (unsigned int j = 0; j < elements_per_wi; j++) {
          T v = g_data[idx + static_cast<long>(j) * stride +
                       static_cast<long>(k) * big_stride];
          for (int i = 0; i < current_compute_iterations; i++) {
            v = KernelOps<T>::add(KernelOps<T>::mul(v, v), seed);
          }
          tmps[j] = v;
        }

        T sum = KernelOps<T>::zero();
        for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2) {
          sum = KernelOps<T>::add(sum, KernelOps<T>::mul(tmps[j], tmps[j + 1]));
        }

        if (KernelOps<T>::equal(sum, KernelOps<T>::minus_one())) {
          g_data[idx + static_cast<long>(k) * big_stride] = sum;
        }
      }
    }
  }
}

void runbench_warmup(void* buffer,
                     long size,
                     size_t workgroupsize,
                     bool block_strided) {
  const long reduced_grid_size = size / 256;
  const int16_t seed = 1;
  run_kernel_typed<int16_t>(buffer, reduced_grid_size, workgroupsize, 1, 1, 0,
                            block_strided, seed);
}

void runbench(const int compute_iterations_arr[],
              unsigned int krn_idx,
              void* buffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer,
              bool block_strided,
              bool enable_dp,
              bool enable_hp) {
  (void)use_os_timer;

  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations_arr[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) *
           (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  constexpr auto total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    double ts_start = now_ms();
    run_kernel_typed<float>(buffer, compute_grid_size, workgroupsize,
                            elements_per_wi, fusion_degree,
                            current_compute_iterations, block_strided, seed_f);
    return now_ms() - ts_start;
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    const double seed_d = 1.0;
    if (enable_dp) {
      double ts_start = now_ms();
      run_kernel_typed<double>(buffer, compute_grid_size, workgroupsize,
                               elements_per_wi, fusion_degree,
                               current_compute_iterations, block_strided, seed_d);
      return now_ms() - ts_start;
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    const Half2 seed_h = make_half2(1.0f, 1.0f);
    if (enable_hp) {
      double ts_start = now_ms();
      run_kernel_typed<Half2>(buffer, compute_grid_size, workgroupsize,
                              elements_per_wi, fusion_degree,
                              current_compute_iterations, block_strided, seed_h);
      return now_ms() - ts_start;
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int32_t seed_i = static_cast<int32_t>(1.0);
    double ts_start = now_ms();
    run_kernel_typed<int32_t>(buffer, compute_grid_size, workgroupsize,
                              elements_per_wi, fusion_degree,
                              current_compute_iterations, block_strided, seed_i);
    return now_ms() - ts_start;
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(Half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(Half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(int dev_id,
                            double* c,
                            long size,
                            bool block_strided,
                            bool host_allocated,
                            bool use_os_timer,
                            size_t workgroupsize,
                            unsigned int elements_per_wi,
                            unsigned int fusion_degree) {
  (void)dev_id;

  const char* benchtype;
  if (block_strided)
    benchtype = "Workgroup";
  else
    benchtype = "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         use_os_timer ? "OS based" : "CL event based");

  bool enable_dp = true;
  bool enable_hp = true;

  void* raw_buffer = nullptr;
  if (posix_memalign(&raw_buffer, 64, static_cast<size_t>(size) * sizeof(double)) !=
      0) {
    fprintf(stderr, "Error: buffer allocation failed\n");
    exit(1);
  }

  std::memset(raw_buffer, 0, static_cast<size_t>(size) * sizeof(double));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");

  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(raw_buffer, size, workgroupsize, block_strided);

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++)
    runbench(compute_iterations, i, raw_buffer, size, workgroupsize,
             elements_per_wi, fusion_degree, use_os_timer, block_strided,
             enable_dp, enable_hp);

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");

  std::memcpy(c, raw_buffer, static_cast<size_t>(size) * sizeof(double));
  free(raw_buffer);
}

int main(int argc, char* argv[]) {
  printf("mixbench-ocl (%s)\n", VERSION_INFO);

  ArgParams args = {1, false, false, false, 256,
                    DEF_VECTOR_SIZE / (1024 * 1024), 8, 4};

  if (!argument_parsing(argc, argv, &args)) {
    printf(
        "Usage: mixbench-ocl [options] [device index [workgroup size [array "
        "size(1024^2) [elements per workitem [fusion degree]]]]]\n");
    printf("\nOptions:\n"
           "  -h or --help              Show this message\n"
           "  -H or --host-alloc        Use host allocated buffer "
           "(CL_MEM_ALLOC_HOST_PTR)\n"
           "  -w or --workgroup-stride  Workitem strides equal to the width "
           "of a workgroup length (default: NDRange length)\n"
           "  -t or --use-os-timer      Use standard OS timer instead of "
           "OpenCL profiling timer\n"
           "\n");

    GetDeviceID(0, stdout);
    exit(1);
  }

  printf("Use \"-h\" argument to see available options\n");

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;
  unsigned int datasize = static_cast<unsigned int>(VEC_WIDTH * sizeof(double));

  int dev_id = GetDeviceID(args.device_index, NULL);

  if (dev_id == 0) {
    fprintf(stderr, "Error: No OpenCL device selected\n");
    exit(1);
  }
  StoreDeviceInfo(dev_id, stdout);

  printf("Buffer size:            %dMB\n", datasize / (1024 * 1024));
  printf("Workgroup size:         %d\n", args.wg_size);
  printf("Elements per workitem:  %d\n", args.elements_per_wi);
  printf("Workitem fusion degree: %d\n", args.fusion_degree);

  if (GetMaxDeviceWGSize(dev_id) < (size_t)args.wg_size) {
    fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", args.wg_size);
    exit(1);
  }

  double* c = (double*)malloc(datasize);
  if (!c) {
    fprintf(stderr, "Error: host allocation failed\n");
    exit(1);
  }

  mixbenchGPU(dev_id, c, static_cast<long>(VEC_WIDTH), args.block_strided,
              args.host_allocated, args.use_os_timer, args.wg_size,
              args.elements_per_wi, args.fusion_degree);

  free(c);

  return 0;
}
